  if (input === "") return 0;

  // Tokenize into terms and operators, e.g. "2U8 + 3U8 - 4U8" => [2U8, +, 3U8, -, 4U8]
  const tokens = input.match(/(-?\d+[UI]\d+|[+\-])/g);
  if (!tokens || tokens.length === 0) {
    throw new Error(`Invalid Tuff value: ${input}`);
  }

  // Parse each term and collect values + types, applying sign from preceding operator
  const parsed: Array<{ value: number; type: string }> = [];
  let sign = 1;

  for (const token of tokens) {
    if (token === "+" || token === "-") {
      // Only treat as binary operator if we already have a term parsed
      if (parsed.length > 0) {
        sign = token === "-" ? -1 : 1;
      } else {
        throw new Error(`Invalid Tuff value: ${input}`);
      }
    } else {
      const match = token.match(/^(-?\d+)([UI]\d+)$/);
      if (!match) throw new Error(`Invalid Tuff value: ${input}`);

      // If the literal itself is negative and we have a minus operator, flip it positive (double negation)
      let valueStr = match[1]!;
      const typeSuffix = match[2]!;

      if (sign === -1 && !valueStr.startsWith("-")) {
        valueStr = "-" + valueStr;
